var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"정말 이래도 돼? 들키면 정학 맞는 거 아냐?","JPN":"本当にいいのか？　バレたら停学処分になるんじゃ……？","ENG":"Are you sure about this? Won't we get suspended if we get caught?","TWN":"真的沒問題嗎？被發現的話會被退學吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그러게 말이야. 그냥 점수 따서 전투 훈련 재끼는 게 낫지 않나......","JPN":"そうだよ。普通に訓練で点数稼いだほうがいいんじゃない？","ENG":"I know, right? Wouldn't it be better to just rake in more points to skip the combat training?","TWN":"就是說啊。還是老老實實參加訓練靠得分完成戰鬥訓練吧……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이제 와서 무슨 겁쟁이 같은 소릴 하는 거야?","JPN":"今更そんな臆病なことを言うの？","ENG":"It's too late to chicken out like that!","TWN":"現在才打退堂鼓，不覺得太晚了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너희들 전부 동의했잖아. 이번 훈련에서 같이 3종 침식체를 사냥하러 가기로.","JPN":"あんたらも同意したでしょ。今回の訓練で一緒に第3種侵食体を狩りに行くって。","ENG":"You guys all agreed to this. We're going to hunt a Category 3 together on this Dive.","TWN":"之前你們不是都同意了嗎。在這次訓練中一起去狩獵3類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"그러긴 했는데......","JPN":"そうは言ったけど……","ENG":"I know, but still...","TWN":"是那樣沒錯……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"역시 막상 닥치니까 나중에 좀 귀찮아질 것 같기도 하고......","JPN":"やっぱり、後で面倒くさいことになりそうだし……","ENG":"I can't help but wonder if we'll get in trouble later...","TWN":"但現在真的很擔心之後會不會有麻煩……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"지금 내 실력을 못 믿겠다는 거야?","JPN":"今の私の実力を信用しないってこと？","ENG":"Are you saying you don't trust my abilities?","TWN":"你們是信不過我的實力嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"난 아카데미 최강의 2종 슬레이어, 나이엘 블루스틸이라고.","JPN":"私はアカデミー最強の2種スレイヤー、ナイエル・ブルースチールなの。","ENG":"I'm Naielle Bluesteel, the Category 2 Slayer! The best the Academy has to offer!","TWN":"我是學院最強的2類屠戮者，奈爾‧布魯斯提爾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 지금까지는 그냥 기회가 없었을 뿐이지. ","JPN":"今までチャンスがなかっただけ。","ENG":"I just never had the chance to prove my true power. ","TWN":"不對，至今也只是沒有機會而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그 재수없는 편입생이 해치운 3종 침식체 따위, 나도 충분히 쓰러뜨릴 수 있어!","JPN":"あの生意気な編入生が倒した第3種侵食体なんか、私だって十分倒せる！","ENG":"If that punk transfer student can take out a Category 3, so can I!","TWN":"那個插班生都能幹掉的3類侵蝕體，我也一定能幹掉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"그, 그래. 나이엘이라면 문제없지.","JPN":"そ、そうだな。ナイエルならできるよ。","ENG":"O-of course. I'm sure you've got this.","TWN":"說的對，奈爾一定沒問題的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그런데 여기선 어떻게 빠져나가게? 자율 방어 시스템이 감시 중이라잖아?","JPN":"でもここからどうやって抜け出すんだ？　自律防御システムが監視しているんだよな？","ENG":"But how are we going to slip out of here? Isn't the ADS monitoring the perimeter?","TWN":"但我們怎麼從這裡溜出去呢？不是說有自主防禦系統在監控嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥. 그럴 줄 알고 내가 다 대책을 마련해 뒀지.","JPN":"ふん。だと思って対策を講じておいたの。","ENG":"Hmpf. I've got a plan for that.","TWN":"哼。我早就做好了萬全的準備。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너희들, 이게 뭔지 알아?","JPN":"あんたたち、これのこと知ってる？","ENG":"Do you guys know what this is?","TWN":"你們知道這是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"뭐야? 무슨...... 기생충처럼 생겼는데?","JPN":"なに？　なんか……寄生虫みたい。","ENG":"What's that? Eww... It looks like a tapeworm or something.","TWN":"是什麼？長得好像……寄生蟲一樣？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"기, 기분 나빠...... 엄청 꿈틀거리잖아......","JPN":"き、気持ち悪い……すごいくねくねしている……","ENG":"C-creepy... It's all wriggly and stuff.","TWN":"真噁心……一直在扭動……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"훈련 전에 블랙 네트워크에서 구해 온 물건이야.","JPN":"訓練前にブラックネットワークから入手したものよ。","ENG":"I got this from the Dark Network before the Dive.","TWN":"這是我在訓練開始前在黑色網路買的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"기계수집가라는 ID를 가진 사람이 팔던 건데, 원리가 뭔지 몰라도 이걸 침투시키면 근처의 기계는 모두 작동이 멈춘다고 했어.","JPN":"機械収集家っていうIDの人が売ってて、原理はわからないけどこれを使えば近くの機械はすべて作動停止するんだって。","ENG":"Some guy with the alias Machine Collector sold it to me. I don't know how it works, but this is supposed to shut down all machines in the area.","TWN":"是網路ID叫機械收藏家的人賣我的道具，雖然不瞭解是什麼原理，但用這個侵入系統就能讓附近的機械都停止運轉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"블랙 네트워크에서 거래한 거야? 대단하다......!","JPN":"ブラックネットワークで取引したって？　すごい……！","ENG":"You made a deal on the Dark Network? That's amazing!","TWN":"你竟然在黑色網路進行交易？真厲害……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그거 잘못 쓰면 좀 위험해지는 거 아냐? ","JPN":"それって使い方間違ったらヤバいやつじゃないか？ ","ENG":"But couldn't it get dangerous if you use that thing? ","TWN":"這東西有點危險吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"자율 방어 시스템이 멈췄을 때 침식체들이 쳐들어 오기라도 하면 어쩌게?","JPN":"自律防御システムが止まった時に侵食体が襲い掛かってきたらどうするんだ？","ENG":"What if the C.O.s attack when the ADS is deactivated?","TWN":"自主防禦系統停止運行後，如果有侵蝕體進攻怎麼辦？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"총학생회장이 말했잖아. 이 근처 침식체들은 이미 모조리 소탕해 버렸다고.","JPN":"生徒会長も言ってたでしょ。付近の侵食体はすでに掃討済みって。","ENG":"Remember what the Student President said? They already wiped out all the C.O.s in the area.","TWN":"學院學生會的會長不是說過了嗎，這周圍的侵蝕體已經全部被消滅掉了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"위험할 일 따윈 전혀 없단 말씀이지!","JPN":"危ないことなんかないから大丈夫！","ENG":"So there's nothing to worry about!","TWN":"就是說不會有任何危險！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그보다 자꾸 말꼬리 잡는 걸 보니 수상한데. 너희들 설마 빠지고 싶어서 그래?","JPN":"ていうか弱音ばっかり吐いて、もしかしてあんたたち乗り気じゃないの？","ENG":"What's with all the fuss anyway? You're not thinking of backing out, are you?","TWN":"不過，你們現在這麼拖拖拉拉，是不是想退出了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"아, 아니야. 얼른 가자.","JPN":"ち、ちがうよ。行こう。","ENG":"O-of course not. Let's go.","TWN":"不、不是。我們快走吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그래, 3종 침식체를 해치우는 영상을 넷튜브에 올리면 조회수가 엄청날걸.","JPN":"そうだね、第3種侵食体を倒す映像をネットチューブにアップしたらすごい再生数稼げそう。","ENG":"Yeah, I'm sure a video of us taking out a Category 3 would go viral on NetTube.","TWN":"嗯。要是把打敗3類侵蝕體的視頻上傳到網路上，點擊量一定會非常火爆。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"좋아. 잠깐 기다려.","JPN":"よし。ちょっと待ってて。","ENG":"Good. Give me a sec.","TWN":"好吧。稍等一下。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"......시스템 경고. 이물질 침입 확인.","JPN":"……システム警告。異物の侵入確認。","ENG":"System warning. Foreign object detected.","TWN":"……系統警告，發現異物侵入系統。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"통제권 상실...... 자율 방어 시스템이 정지됩니다.","JPN":"コントロール不可……自律防御システムが停止します。","ENG":"Control authority compromised... Suspending ADS operation.","TWN":"失去控制許可權……自主防禦系統已停止運行。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"지금이야! 다들 달려!","JPN":"今だ！　みんな走って！","ENG":"Now! Run!","TWN":"就是現在！快跑！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};